/** Initialize snapshot tracking for a directory. Idempotent. */
export async function init(dir: string): Promise<{ backend: SnapshotBackend }> {
  // Validate the input at the API boundary so callers get a clear error
  // instead of a stray .refine/ appearing under a typo'd path (Deno.mkdir
  // with recursive:true would otherwise silently create it).
  if (typeof dir !== "string" || dir.length === 0) {
    throw new Error(
      `init: dir must be a non-empty string (got ${JSON.stringify(dir)})`,
    );
  }
  let stat: Deno.FileInfo;
  try {
    stat = await Deno.stat(dir);
  } catch {
    throw new Error(`init: directory does not exist: ${dir}`);
  }
  if (!stat.isDirectory) {
    throw new Error(`init: path is not a directory: ${dir}`);
  }

  const backend = await detectBackend(dir);
  const refineDir = join(dir, REFINE_DIR);

Deno.test("init: rejects non-existent dir, empty string, and non-directory paths", async () => {
  // Non-existent path — must not silently create a .refine/ under it.
  const phantom = await Deno.makeTempDir({ prefix: "snapshot-test-" });
  await Deno.remove(phantom, { recursive: true });
  let threw = false;
  try { await init(phantom); }
  catch (err) { threw = true; assertStringIncludes(String(err), "does not exist"); }
  assert(threw, "init on non-existent dir must throw");
  assertEquals(await exists(phantom), false, "init must not create the missing dir");

  // Empty string.
  threw = false;
  try { await init(""); }
  catch (err) { threw = true; assertStringIncludes(String(err), "non-empty string"); }
  assert(threw, "init on empty string must throw");

  // A file, not a directory.
  const parent = await makeTempDir();
  try {
    const filePath = join(parent, "not-a-dir");
    await Deno.writeTextFile(filePath, "hi");
    threw = false;
    try { await init(filePath); }
    catch (err) { threw = true; assertStringIncludes(String(err), "not a directory"); }
    assert(threw, "init on a file path must throw");
  } finally {
    await cleanup(parent);
  }
});

